INSERT INTO public.flash_news VALUES (41, 'Chaos Labs退出Aave DAO', '关键贡献者Chaos Labs宣布退出Aave DAO。此前，BGD和ACI也已离开该去中心化自治组织。', '', NULL, 2, 'normal', '2026-04-07 11:26:35', '2026-04-07 11:26:35', '2026-04-07 11:26:27', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (42, 'Binance to Delist Multiple Perpetuals', 'Binance Futures will delist several perpetual contracts on April 8 and April 9, 2026. Users are advised to manage their positions and orders accordingly before the delisting dates.', '', NULL, 2, 'normal', '2026-04-07 11:26:38', '2026-04-07 11:26:38', '2026-04-07 11:26:27', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (43, 'Drift Hack Probe: NK Intermediaries Involved', 'A preliminary investigation into the Drift Protocol hack indicates team members were approached in person at conferences by North Korean intermediaries, according to a post on X.', '', NULL, 2, 'normal', '2026-04-07 11:26:40', '2026-04-07 11:26:40', '2026-04-07 11:26:27', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (44, 'Chaos Labs Exits Aave DAO', 'Key contributor Chaos Labs has left the Aave DAO, following the earlier departures of BGD and ACI. The exit was noted in the project''s governance forum.', '', NULL, 2, 'normal', '2026-04-07 11:26:42', '2026-04-07 11:26:42', '2026-04-07 11:26:27', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (45, 'Everbright Futures: Oil Market Daily', 'Everbright Futures'' daily report notes that while a ceasefire agreement faces complications, oil prices retain upward support. Market volatility persisted during the recent holiday period.', '', NULL, 3, 'normal', '2026-04-07 11:26:45', '2026-04-07 11:26:45', '2026-04-07 11:26:27', 'en', 'commodity') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (46, '特朗普言论推高油价', '路透社报道，随着特朗普对伊朗的言论趋于强硬，原油价格延续涨势。', '', NULL, 2, 'normal', '2026-04-07 11:26:47', '2026-04-07 11:26:47', '2026-04-07 11:26:27', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (47, 'Phillips 66因油价上涨面临9亿美元亏损', '路透社报道，由于伊朗危机推高油价，美国炼油商Phillips 66面临高达9亿美元的衍生品亏损。', '', NULL, 2, 'normal', '2026-04-07 11:26:49', '2026-04-07 11:26:49', '2026-04-07 11:26:27', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (48, 'Chaos Labs退出Aave风险提供商角色', 'DeFi风险管理者Chaos Labs表示，Aave计划迁移至V4版本引入了其不愿承担的风险，因此决定退出。Aave方面则表示Chaos Labs希望作为唯一风险服务提供商获得完全控制权。', '', NULL, 2, 'normal', '2026-04-07 11:26:52', '2026-04-07 11:26:52', '2026-04-07 11:26:27', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (49, 'Polymarket升级交易所并更换稳定币', 'Polymarket将在未来几周升级其交易所基础设施，引入新合约和USDC背书的代币，同时逐步淘汰桥接稳定币USDC.e。', '', NULL, 2, 'normal', '2026-04-07 11:26:54', '2026-04-07 11:26:54', '2026-04-07 11:26:27', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (50, '币安合约将下架多个永续合约', '币安合约交易平台发布公告，计划于2026年4月8日及4月9日下架多个永续合约。此举是定期市场审查的一部分，旨在优化产品线并提升流动性。建议相关用户提前管理仓位。', '', NULL, 2, 'normal', '2026-04-07 11:27:33', '2026-04-07 11:27:33', '2026-04-07 11:27:31', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (51, 'Chaos Labs退出Aave DAO', 'DeFi风险管理服务商Chaos Labs宣布退出Aave DAO，成为继BGD和ACI之后又一家离开的关键贡献者。此举可能影响Aave协议未来的风险管理与治理结构。', '', NULL, 2, 'normal', '2026-04-07 11:27:38', '2026-04-07 11:27:38', '2026-04-07 11:27:31', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (52, '特朗普对伊言论推高油价', '路透社报道，随着美国前总统特朗普对伊朗的言论趋于强硬，国际油价延续涨势。地缘政治紧张局势升级加剧了市场对全球石油供应中断的担忧。', 'Reuters', NULL, 2, 'normal', '2026-04-07 11:27:40', '2026-04-07 11:27:40', '2026-04-07 11:27:31', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (53, 'Phillips 66因油价上涨面临9亿美元亏损', '路透社报道，炼油商Phillips 66表示，因伊朗危机推高油价，导致其衍生品头寸面临高达9亿美元的潜在亏损。这凸显了能源企业在价格剧烈波动下面临的风险。', 'Reuters', NULL, 2, 'normal', '2026-04-07 11:27:42', '2026-04-07 11:27:42', '2026-04-07 11:27:31', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (54, 'Jim Cramer：市场底取决于利率而非战争', 'CNBC评论员Jim Cramer表示，投资者不应因战争头条新闻而轻易判断市场已触底。他认为，驱动当前市场的真正因素是利率前景，而非地缘政治。', '', NULL, 2, 'normal', '2026-04-07 11:27:44', '2026-04-07 11:27:44', '2026-04-07 11:27:31', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (55, 'Chaos Labs辞任Aave风险服务商', 'DeFi风险管理者Chaos Labs宣布辞去Aave协议风险服务提供商职务，称Aave向V4版本的迁移计划引入了其不愿承担的风险。Aave方面则表示，Chaos Labs希望作为唯一风险服务商获得完全控制权。', '', NULL, 2, 'normal', '2026-04-07 11:27:47', '2026-04-07 11:27:47', '2026-04-07 11:27:31', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (56, 'Polymarket升级交易所并更换稳定币', '预测市场Polymarket宣布将在未来几周进行全面的交易所升级，引入新合约并以USDC原生代币替代原有的跨链桥接稳定币USDC.e，以提升系统安全性与效率。', '', NULL, 2, 'normal', '2026-04-07 11:27:49', '2026-04-07 11:27:49', '2026-04-07 11:27:31', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (57, 'Strategy大量买入或推高比特币至11万美元', '分析指出，由于投资机构Strategy在短短一个多月内买入46,233枚BTC，远超同期16,200枚的新增供应量，比特币可能打破看跌旗形形态，价格或上行至11万美元。', '', NULL, 2, 'normal', '2026-04-07 11:27:51', '2026-04-07 11:27:51', '2026-04-07 11:27:31', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (58, '比特币期权市场暗示重大下行风险', '比特币期权市场的定价数据正悄然反映出对价格可能出现重大下行波动的预期。衍生品交易员正在为潜在的市场回调进行对冲。', '', NULL, 2, 'normal', '2026-04-07 11:27:53', '2026-04-07 11:27:53', '2026-04-07 11:27:31', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (59, 'Jamie Dimon警示区块链与稳定币带来新竞争', '摩根大通CEO杰米·戴蒙在年度致股东信中警告，区块链、代币化和稳定币等新技术正在重塑金融业，为传统银行带来新的竞争对手。同时，该行也在扩大其自身的区块链网络。', '', NULL, 2, 'normal', '2026-04-07 11:27:55', '2026-04-07 11:27:55', '2026-04-07 11:27:31', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (60, '美参议员确认4月推进加密市场结构法案', '美国参议院银行委员会成员Bill Hagerty确认，国会将在4月重新关注并推进加密货币市场结构立法工作。他承认在法案取得进展前“仍有大量工作要做”。', '', NULL, 2, 'normal', '2026-04-07 11:27:57', '2026-04-07 11:27:57', '2026-04-07 11:27:31', 'zh', '') ON CONFLICT DO NOTHING;
