INSERT INTO public.flash_news VALUES (62, '特朗普言论推高油价', '路透社报道，随着特朗普对伊朗的言辞升级，石油价格延续涨势。地缘政治紧张局势加剧了市场对供应中断的担忧。', '原source', NULL, 2, 'normal', '2026-04-07 11:28:25', '2026-04-07 11:28:25', '2026-04-07 11:28:23', 'zh', '') ON CONFLICT DO NOTHING;
