INSERT INTO public.flash_news VALUES (78, 'Analyst Maps Bitcoin to $215K', 'A crypto analyst has outlined a roadmap for Bitcoin, predicting the price could reach $215,000. The analysis interprets past cycles and market psychology.', '', NULL, 2, 'normal', '2026-04-07 11:29:39', '2026-04-07 11:29:39', '2026-04-07 11:29:28', 'en', '') ON CONFLICT DO NOTHING;
