INSERT INTO public.flash_news VALUES (80, 'Ethereum Faces 60% Drop Odds', 'Polymarket gives Ethereum a 60% chance of losing its position as the second-largest cryptocurrency. ETH fell over 30% in Q1, though Standard Chartered maintains a $7,500 year-end target.', '', NULL, 2, 'normal', '2026-04-07 11:29:43', '2026-04-07 11:29:43', '2026-04-07 11:29:28', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (81, 'NZD/USD Plunges to 0.5700', 'The New Zealand Dollar has slumped sharply against the US Dollar, with NZD/USD trading near 0.5700. Geopolitical fears and the upcoming RBNZ policy decision are key drivers.', '', NULL, 2, 'normal', '2026-04-07 11:29:45', '2026-04-07 11:29:45', '2026-04-07 11:29:28', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (82, 'CoinRabbit Cuts XRP Loan Rates', 'CoinRabbit has reduced crypto lending rates for XRP loans and over 300 other assets, making borrowing more cost-effective for users.', '', NULL, 2, 'normal', '2026-04-07 11:29:47', '2026-04-07 11:29:47', '2026-04-07 11:29:28', 'en', '') ON CONFLICT DO NOTHING;
