INSERT INTO public.flash_news VALUES (84, 'Bitcoin Muted Above $66K', 'Bitcoin price is trading quietly above $66,000 as markets focus on the Iran conflict and upcoming U.S. jobs data for directional cues.', '', NULL, 2, 'normal', '2026-04-07 11:29:51', '2026-04-07 11:29:51', '2026-04-07 11:29:28', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (85, 'Solana Drops 2.7% to $79.81', 'Solana (SOL) is trading at $79.81, down 2.7% over the past 24 hours. Its market capitalization stands at approximately $45.8 billion.', '', NULL, 2, 'normal', '2026-04-07 11:29:54', '2026-04-07 11:29:54', '2026-04-07 11:29:28', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (86, '伊朗称海峡不会重开', '据彭博社报道，伊朗方面表示，基于特朗普的“荒谬”表现，霍尔木兹海峡不会重新开放。此举加剧了地缘政治紧张局势。', '', NULL, 2, 'normal', '2026-04-07 11:30:27', '2026-04-07 11:30:27', '2026-04-07 11:30:25', 'zh', '') ON CONFLICT DO NOTHING;
