INSERT INTO public.flash_news VALUES (88, '光大期货：油价上行有支撑', '光大期货分析指出，尽管中东停火协议存在曲折，但地缘政治风险仍为油价提供上行支撑。假期期间国际油价波动反复，市场关注后续局势发展。', '', NULL, 3, 'normal', '2026-04-07 11:30:31', '2026-04-07 11:30:31', '2026-04-07 11:30:25', 'zh', 'futures') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (89, 'Chaos Labs退出Aave风险服务', 'DeFi风险管理商Chaos Labs宣布不再担任Aave的风险服务提供商，称Aave计划向V4版本的迁移引入了其不愿承担的风险。Aave则表示Chaos Labs希望成为唯一的风险服务商。', '', NULL, 2, 'normal', '2026-04-07 11:30:33', '2026-04-07 11:30:33', '2026-04-07 11:30:25', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (90, '比特币期权市场暗示大跌', '比特币期权市场的定价数据正悄然反映市场对一次重大下行波动的预期，表明部分交易者正为价格大幅下跌做准备。', '', NULL, 2, 'normal', '2026-04-07 11:30:36', '2026-04-07 11:30:36', '2026-04-07 11:30:25', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (91, '美参议院拟推进加密法案', '美国参议院银行委员会成员确认，关于加密货币市场结构的立法工作将于4月启动。参议员比尔·哈格蒂承认在国会推进法案前“仍有大量工作要做”。', '', NULL, 2, 'normal', '2026-04-07 11:30:38', '2026-04-07 11:30:38', '2026-04-07 11:30:25', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (92, '以太坊价格回调但获支撑', '以太坊价格在突破2150美元后遭遇卖压，目前正进行回调。技术分析显示，ETH在2080美元区域附近可能获得买盘支撑，整体结构仍保持稳固。', '', NULL, 2, 'normal', '2026-04-07 11:30:40', '2026-04-07 11:30:40', '2026-04-07 11:30:25', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (93, '孙宇晨在EthCC谈AI支付', 'TRON创始人孙宇晨在以太坊社区大会（EthCC）上强调了TRON网络在赋能AI代理支付方面的潜力。TRON DAO同时作为红宝石赞助商参与了此次活动。', '', NULL, 2, 'normal', '2026-04-07 11:30:42', '2026-04-07 11:30:42', '2026-04-07 11:30:25', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (94, '分析师预测比特币将达21.5万', '一位加密货币分析师发布了对比特币周期的新解读，预测其价格可能在当前周期内达到21.5万美元，并分享了市场在关键阶段的心理洞察。', '', NULL, 2, 'normal', '2026-04-07 11:30:45', '2026-04-07 11:30:45', '2026-04-07 11:30:25', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (95, '韩国强制交易所5分钟对账', '在Bithumb发生数十亿美元的错误派息事件后，韩国金融委员会出台新规，要求国内加密货币交易所每五分钟检查一次用户资产余额，以加强风险控制。', '', NULL, 2, 'normal', '2026-04-07 11:30:47', '2026-04-07 11:30:47', '2026-04-07 11:30:25', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (96, '以太坊或失第二大加密地位', '预测市场Polymarket数据显示，以太坊有60%的几率失去其市值第二大加密货币的地位。此前ETH在第一季度下跌超30%，但渣打银行仍维持其7500美元的年底目标价。', '', NULL, 2, 'normal', '2026-04-07 11:30:49', '2026-04-07 11:30:49', '2026-04-07 11:30:25', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (97, '纽元暴跌，关注新西兰联储', '受地缘政治担忧加剧影响，纽元兑美元汇率暴跌至0.5700关口附近。市场正密切关注即将公布的新西兰联储利率决议，以寻求政策指引。', '', NULL, 2, 'normal', '2026-04-07 11:30:51', '2026-04-07 11:30:51', '2026-04-07 11:30:25', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (98, '币安将上线MU和SNDK股票永续合约', '币安合约交易平台宣布，将于2026年4月7日上线MUUSDT和SNDKUSDT的美元本位股权永续合约。用户将能够交易美光科技和SanDisk相关股票的衍生品。', '', NULL, 2, 'normal', '2026-04-07 11:31:34', '2026-04-07 11:31:34', '2026-04-07 11:31:32', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (99, '币安合约将下架多个永续合约', '币安合约发布公告，计划于2026年4月8日及4月9日下架多个永续合约。交易所通常定期评估并下架流动性不足或需求较低的交易对，以优化产品线。', '', NULL, 2, 'normal', '2026-04-07 11:31:36', '2026-04-07 11:31:36', '2026-04-07 11:31:32', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (100, 'Chaos Labs退出AAVE DAO', '关键贡献者Chaos Labs宣布离开AAVE去中心化自治组织(DAO)。此前，Blockchain Governance DAO (BGD)和Aave Companies Inc (ACI)也已退出。核心贡献者的连续离开可能影响AAVE协议的治理与发展。', '', NULL, 2, 'normal', '2026-04-07 11:31:38', '2026-04-07 11:31:38', '2026-04-07 11:31:32', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (101, 'Chaos Labs退出Aave风险提供商角色', 'DeFi风险管理器Chaos Labs宣布不再担任Aave的风险服务提供商，称该决定“并非仓促做出”。Chaos Labs表示，Aave计划向V4版本的迁移引入了其不愿承担的风险。', '', NULL, 2, 'normal', '2026-04-07 11:31:40', '2026-04-07 11:31:40', '2026-04-07 11:31:32', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (102, '比特币期权市场暗示大幅下行风险', '比特币期权市场的定价数据正悄然反映市场对价格可能出现大幅下行的预期。衍生品交易员可能正在通过期权合约对冲潜在的市场下跌风险。', '', NULL, 2, 'normal', '2026-04-07 11:31:42', '2026-04-07 11:31:42', '2026-04-07 11:31:32', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (103, '以太坊价格回调但结构获支撑', '以太坊价格在突破2150美元后遭遇卖压，目前正进行回调。关键技术支撑位在2080美元附近。ETH仍交投于2100美元及100小时均线上方，整体上行结构未遭破坏。', '', NULL, 2, 'normal', '2026-04-07 11:31:45', '2026-04-07 11:31:45', '2026-04-07 11:31:32', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (104, '分析师预测比特币将达21.5万美元', '一位加密货币分析师发布了比特币周期交易路线图，解读了过去市场事件并预测未来数月走势。该分析师预测比特币价格最终将达到21.5万美元，并分享了当前周期关键阶段的市场心理洞察。', '', NULL, 2, 'normal', '2026-04-07 11:31:47', '2026-04-07 11:31:47', '2026-04-07 11:31:32', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (105, '韩国强制交易所每5分钟核对余额', '韩国金融委员会(FSC)出台新规，要求国内加密货币交易所每五分钟核对一次用户资产余额。此项规定是在Bithumb发生数十亿美元的错误派息事故后引入的，旨在加强用户资产保护。', '', NULL, 2, 'normal', '2026-04-07 11:31:49', '2026-04-07 11:31:49', '2026-04-07 11:31:32', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (106, 'Polymarket预测以太坊六成概率失亚军', '预测市场Polymarket数据显示，以太坊有60%的几率失去其加密货币市值第二的排名。此前ETH在第一季度下跌超过30%。不过，渣打银行仍维持其7500美元的年底目标价。', '', NULL, 2, 'normal', '2026-04-07 11:31:51', '2026-04-07 11:31:51', '2026-04-07 11:31:32', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (107, '纽元兑美元暴跌至0.57关口', '新西兰元兑美元汇率大幅下挫，交投于0.5700关口附近。这一显著走弱主要源于中东地缘政治紧张局势加剧引发的避险情绪。市场焦点转向新西兰联储即将做出的关键利率决议。', '', NULL, 2, 'normal', '2026-04-07 11:31:53', '2026-04-07 11:31:53', '2026-04-07 11:31:32', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (108, 'CoinRabbit降低XRP等资产借贷利率', '加密货币借贷平台CoinRabbit宣布降低其XRP贷款及超过300种其他资产的借贷利率。此举旨在吸引更多用户使用其质押借贷服务，降低用户融资成本。', '', NULL, 2, 'normal', '2026-04-07 11:31:55', '2026-04-07 11:31:55', '2026-04-07 11:31:32', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (109, 'Strategy报告买入比特币并出售股票', '投资机构Strategy报告了其近期操作，包括买入比特币并出售部分股票资产。此举反映了机构投资者可能正在调整其资产配置，增加对加密货币的敞口。', '', NULL, 2, 'normal', '2026-04-07 11:31:57', '2026-04-07 11:31:57', '2026-04-07 11:31:32', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (110, 'Binance to Delist Perpetual Contracts', 'Binance Futures will delist multiple perpetual contracts on April 8 and 9, 2026. The exchange regularly reviews its offerings and may remove low-liquidity contracts to maintain market quality.', '', NULL, 2, 'normal', '2026-04-07 11:32:28', '2026-04-07 11:32:28', '2026-04-07 11:32:26', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (111, '特朗普对伊言论推高油价', '路透社报道，随着特朗普对伊朗的言辞趋于尖锐，原油价格延续涨势。地缘政治风险溢价上升，继续为国际油价提供支撑。', 'Reuters', NULL, 2, 'normal', '2026-04-07 11:32:31', '2026-04-07 11:32:31', '2026-04-07 11:32:26', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (112, '以太坊价格回调但结构稳固', '以太坊价格在突破2150美元后遭遇卖压，目前正进行回调，可能在2080美元附近获得支撑。ETH仍交投于2100美元及100小时均线上方，整体结构保持稳固。', '', NULL, 2, 'normal', '2026-04-07 11:32:33', '2026-04-07 11:32:33', '2026-04-07 11:32:26', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (113, '纽元兑美元暴跌至0.5700', '受地缘政治担忧加剧影响，新西兰元兑美元汇率大幅下挫，一度逼近0.5700关口。市场正密切关注新西兰联储即将做出的关键政策决议。', '', NULL, 2, 'normal', '2026-04-07 11:32:35', '2026-04-07 11:32:35', '2026-04-07 11:32:26', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (114, 'CoinRabbit降低XRP等资产借贷利率', '加密货币借贷平台CoinRabbit宣布，将下调XRP贷款及平台上300多种其他资产的借贷利率，以吸引更多用户并提升平台竞争力。', '', NULL, 2, 'normal', '2026-04-07 11:32:37', '2026-04-07 11:32:37', '2026-04-07 11:32:26', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (115, 'Strategy报告买入比特币并卖出股票', '投资机构Strategy在其最新活动报告中披露，近期进行了买入比特币并同时卖出股票的操作。此举反映了其对不同资产类别的策略性调整。', '', NULL, 2, 'normal', '2026-04-07 11:32:40', '2026-04-07 11:32:40', '2026-04-07 11:32:26', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (333, 'Chaos Labs退出Aave DAO', '关键贡献者Chaos Labs宣布退出Aave DAO。此前，BGD和ACI也已离开，显示该DeFi协议治理结构面临调整。', '', NULL, 2, 'normal', '2026-04-07 11:56:23', '2026-04-07 11:56:23', '2026-04-07 11:56:19', 'zh', '') ON CONFLICT DO NOTHING;
