INSERT INTO public.flash_news VALUES (118, 'Dogecoin 24小时跌2.2%', 'Dogecoin (DOGE) 当前报价0.09美元，过去24小时下跌2.2%，市值约为139亿美元。作为主流Meme币，DOGE价格走势与市场整体风险偏好相关。', '', NULL, 2, 'normal', '2026-04-07 11:32:46', '2026-04-07 11:32:46', '2026-04-07 11:32:26', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (119, 'Cardano 24小时跌4.5%', 'Cardano (ADA) 当前报价0.25美元，过去24小时下跌4.5%，市值约为90亿美元。ADA跌幅大于市场平均水平，显示其近期抛压较重。', '', NULL, 2, 'normal', '2026-04-07 11:32:48', '2026-04-07 11:32:48', '2026-04-07 11:32:26', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (120, 'Canton 24小时涨5.8%', 'Canton (CC) 当前报价0.15美元，过去24小时逆市上涨5.8%，市值约为56亿美元。其独立行情可能受到特定项目进展或市场消息推动。', '', NULL, 2, 'normal', '2026-04-07 11:32:50', '2026-04-07 11:32:50', '2026-04-07 11:32:26', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (121, 'Dogecoin Falls 2.2% to $0.09', 'Dogecoin (DOGE) is priced at $0.09, marking a 24-hour decline of 2.2%. The meme coin''s market cap is around $13.9 billion as it follows the general downward trend in the crypto market.', '', NULL, 2, 'normal', '2026-04-07 11:32:52', '2026-04-07 11:32:52', '2026-04-07 11:32:26', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (122, 'China Fines Utilities $235M Over Fees', 'China''s market regulator has fined utility companies a total of 235 million yuan ($35M approx.) for improper metering and fee collection. The campaign, running from May 2025 to Jan 2026, involved over 14,000 cases.', '', NULL, 2, 'normal', '2026-04-07 11:33:34', '2026-04-07 11:33:34', '2026-04-07 11:33:32', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (123, 'Local Banks Pilot JPM Coin in Argentina', 'Several Argentine banking institutions are trialing JPMorgan''s JPM Coin to streamline interbank settlements. The move comes as regulators evaluate lifting the ban on banks offering crypto services.', '', NULL, 2, 'normal', '2026-04-07 11:33:36', '2026-04-07 11:33:36', '2026-04-07 11:33:32', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (124, 'Dogecoin Falls 2.2% to $0.09', 'Dogecoin (DOGE) is priced at $0.09, marking a 24-hour decline of 2.2%. The meme coin''s market cap is around $13.9 billion.', '', NULL, 2, 'normal', '2026-04-07 11:33:38', '2026-04-07 11:33:38', '2026-04-07 11:33:32', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (125, 'Cardano Down 4.5% to $0.25', 'Cardano (ADA) has decreased by 4.5% in the last day, trading at $0.25. Its market capitalization is estimated at $9.0 billion.', '', NULL, 2, 'normal', '2026-04-07 11:33:40', '2026-04-07 11:33:40', '2026-04-07 11:33:32', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (126, 'Canton Rises 5.9% to $0.15', 'Canton (CC) is up 5.9% over 24 hours, with its price reaching $0.15. The token''s market cap is approximately $5.6 billion.', '', NULL, 2, 'normal', '2026-04-07 11:33:42', '2026-04-07 11:33:42', '2026-04-07 11:33:32', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (127, '币安将上线MUUSDT和SNDKUSDT永续合约', '币安合约平台计划于2026年4月7日上线MUUSDT和SNDKUSDT的美元本位股权永续合约。新合约将为用户提供交易美光科技和闪迪相关衍生品的机会。', '原source', NULL, 2, 'normal', '2026-04-07 11:34:31', '2026-04-07 11:34:31', '2026-04-07 11:34:29', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (128, '币安合约将下架多个永续合约', '币安合约发布公告，将于2026年4月8日及4月9日下架多个永续合约。此举是平台定期对流动性不足或交易需求低的合约进行梳理的一部分，建议用户提前管理仓位。', '原source', NULL, 2, 'normal', '2026-04-07 11:34:33', '2026-04-07 11:34:33', '2026-04-07 11:34:29', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (129, 'Chaos Labs退出AAVE DAO', '关键贡献者Chaos Labs宣布离开AAVE DAO。此前，BGD和ACI也已退出。Chaos Labs的离开可能与AAVE计划迁移至V4版本引入的风险有关，该团队不愿承担相关风险。', '原source', NULL, 2, 'normal', '2026-04-07 11:34:35', '2026-04-07 11:34:35', '2026-04-07 11:34:29', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (130, 'Strategy Buys 46K BTC in a Month', 'Strategy purchased 46,233 Bitcoin in just over a month, nearly triple the new BTC supply mined in the same period. This demand could push Bitcoin toward $110,000.', '', NULL, 2, 'normal', '2026-04-07 11:34:38', '2026-04-07 11:34:38', '2026-04-07 11:34:29', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (131, '阿根廷本地银行试点摩根大通JPM Coin', '多家阿根廷银行机构正在试点摩根大通的JPM Coin，以简化银行间结算流程。此举旨在利用该代币在成本、速度和效率方面的优势。同时，监管机构正在评估解除银行提供加密服务的禁令。', '原source', NULL, 2, 'normal', '2026-04-07 11:34:40', '2026-04-07 11:34:40', '2026-04-07 11:34:29', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (132, 'Strategy报告买入比特币并卖出股票', '投资机构Strategy报告了其近期操作，包括买入比特币和卖出股票的活动。具体数据显示，该机构在一个多月内购买了46,233枚BTC，超过了同期16,200枚BTC的新供应量。', '原source', NULL, 2, 'normal', '2026-04-07 11:34:42', '2026-04-07 11:34:42', '2026-04-07 11:34:29', 'zh', '') ON CONFLICT DO NOTHING;
