INSERT INTO public.flash_news VALUES (354, 'Phillips 66预计衍生品亏损达10亿美元', '炼油商Phillips 66预计，由于油价上涨导致其对冲头寸出现亏损，公司衍生品损失可能高达10亿美元。这反映了能源企业在价格剧烈波动下面临的风险。', '', NULL, 3, 'normal', '2026-04-07 11:59:30', '2026-04-07 11:59:30', '2026-04-07 11:59:21', 'zh', 'commodity') ON CONFLICT DO NOTHING;
