INSERT INTO public.flash_news VALUES (359, '美国页岩油商预计将增产', '受战争驱动的油价上涨影响，美国页岩油生产商终于有望提高原油产量，这可能在未来几个月增加全球石油供应。', '', NULL, 2, 'normal', '2026-04-07 12:00:40', '2026-04-07 12:00:40', '2026-04-07 12:00:31', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (360, '光大期货：油价上行仍有支撑', '光大期货分析指出，假期期间油价波动反复，但停火协议存在曲折，预计油价上行仍有支撑。市场关注地缘政治局势对能源供应的潜在影响。', '', NULL, 3, 'normal', '2026-04-07 12:01:34', '2026-04-07 12:01:34', '2026-04-07 12:01:32', 'zh', 'futures') ON CONFLICT DO NOTHING;
