INSERT INTO public.flash_news VALUES (485, '比特币期权市场暗示重大下行风险', '比特币期权市场的定价结构正悄然反映一次重大的下行风险。衍生品交易员通过期权头寸布局，表明对市场短期深度回调的担忧正在加剧。', '', NULL, 2, 'normal', '2026-04-07 12:12:48', '2026-04-07 12:12:48', '2026-04-07 12:12:23', 'zh', '') ON CONFLICT DO NOTHING;
