INSERT INTO public.flash_news VALUES (495, '霍尔木兹紧张局势推动美元飙升，金价暴跌', '受中东霍尔木兹海峡地缘政治紧张局势升级以及对美联储鹰派政策预期转变的共同影响，美元走强，黄金价格本周延续跌势。', '', NULL, 2, 'normal', '2026-04-07 12:13:40', '2026-04-07 12:13:40', '2026-04-07 12:13:18', 'zh', '') ON CONFLICT DO NOTHING;
