INSERT INTO public.flash_news VALUES (677, 'Strategy报告比特币购买与股票出售活动', '投资机构Strategy报告了其近期的比特币购买与股票出售活动，显示出其资产配置向加密货币倾斜的策略调整。', '', NULL, 2, 'normal', '2026-04-07 12:30:38', '2026-04-07 12:30:38', '2026-04-07 12:30:27', 'zh', '') ON CONFLICT DO NOTHING;
