INSERT INTO public.flash_news VALUES (679, '加密市场安全港法案送白宫审查', '旨在为加密项目提供监管明确性的“安全港”法案草案已提交至白宫进行审查，这被视为美国加密货币监管框架向前迈出的关键一步。', '', NULL, 2, 'normal', '2026-04-07 12:30:43', '2026-04-07 12:30:43', '2026-04-07 12:30:27', 'zh', '') ON CONFLICT DO NOTHING;
