INSERT INTO public.flash_news VALUES (681, '医保费率上调推动保险股上涨', '由于联邦医疗保险优势计划(Medicare Advantage)费率获得上调，Humana、UnitedHealth等主要保险公司的股价应声跳涨，领跑市场。', '', NULL, 2, 'normal', '2026-04-07 12:30:47', '2026-04-07 12:30:47', '2026-04-07 12:30:27', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (682, '巴西国油高层变动', '巴西国家石油公司(Petrobras)进行领导层改组，Pogliese被任命为新任董事长，此举可能影响公司未来的战略方向。', '', NULL, 2, 'normal', '2026-04-07 12:30:49', '2026-04-07 12:30:49', '2026-04-07 12:30:27', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (683, '伊朗称不会因特朗普言论重开海峡', '据彭博社报道，伊朗方面表示，不会基于特朗普的“荒谬”表现而重新开放关键海峡。此番言论加剧了地缘政治紧张局势。', '', NULL, 2, 'normal', '2026-04-07 12:31:29', '2026-04-07 12:31:29', '2026-04-07 12:31:27', 'zh', '') ON CONFLICT DO NOTHING;
