INSERT INTO public.flash_news VALUES (743, '币安将上线MU和SNDK股票永续合约', '币安合约交易平台将于2026年4月7日上线MUUSDT和SNDKUSDT的美元本位股票永续合约。新合约允许用户交易美光科技和闪迪等公司的股票敞口。', '', NULL, 2, 'normal', '2026-04-07 12:36:30', '2026-04-07 12:36:30', '2026-04-07 12:36:23', 'zh', '') ON CONFLICT DO NOTHING;
