INSERT INTO public.flash_news VALUES (749, 'Polymarket Overhauls with USDC Token', 'Polymarket is upgrading its exchange infrastructure, introducing new contracts and a native USDC-backed token while phasing out the bridged USDC.e stablecoin.', '', NULL, 2, 'normal', '2026-04-07 12:36:43', '2026-04-07 12:36:43', '2026-04-07 12:36:23', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (750, '主要加密货币持稳，关注伊朗局势', '比特币、以太坊和Solana价格持稳。特朗普为伊朗协议设定周二午夜最后期限，威胁若无协议将摧毁伊朗基础设施，油价跳涨至112美元上方，加密市场回吐涨幅。', '', NULL, 2, 'normal', '2026-04-07 12:36:45', '2026-04-07 12:36:45', '2026-04-07 12:36:23', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (751, '比特币跌破6.7万美元', '在特朗普威胁将对伊朗采取“极其强硬”措施后，比特币价格下滑，跌破6.7万美元关口。地缘政治风险加剧引发市场避险情绪，打压风险资产。', '', NULL, 2, 'normal', '2026-04-07 12:36:47', '2026-04-07 12:36:47', '2026-04-07 12:36:23', 'zh', '') ON CONFLICT DO NOTHING;
