INSERT INTO public.flash_news VALUES (1416, 'Chaos Labs Exits Aave DAO', 'Key contributor Chaos Labs has left the Aave DAO, following the earlier exits of BGD and ACI. The risk management firm cited concerns over risks associated with Aave''s planned migration to V4.', '', NULL, 2, 'normal', '2026-04-07 13:44:21', '2026-04-07 13:44:21', '2026-04-07 13:44:17', 'en', '') ON CONFLICT DO NOTHING;
