INSERT INTO public.flash_news VALUES (1441, '金价持稳 特朗普最后期限令市场谨慎', '据路透社报道，黄金价格保持稳定。特朗普总统给伊朗设定的最后期限令金融市场保持谨慎态度。', '', NULL, 2, 'normal', '2026-04-07 13:48:30', '2026-04-07 13:48:30', '2026-04-07 13:48:28', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (1543, 'Canton24小时上涨6.5%', 'Canton（CC）当前价格为0.15美元，过去24小时上涨6.5%，市值约为57亿美元。', '', NULL, 2, 'normal', '2026-04-07 14:00:52', '2026-04-07 14:00:52', '2026-04-07 14:00:35', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (708, 'Polymarket采用Pyth Pro支持传统资产市场', '预测市场平台Polymarket宣布采用Pyth Pro为其传统资产市场提供数据支持。Pyth Pro是去中心化预言机网络，旨在为链上应用提供高质量、实时的金融市场数据。', '', NULL, 2, 'normal', '2026-04-07 12:33:36', '2026-04-07 12:33:36', '2026-04-07 12:33:27', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (709, '币安合约将下架多个永续合约', '币安合约宣布将于2026年4月8日及4月9日下架多个永续合约。交易所定期审查合约表现，下架流动性不足或交易需求低的合约是标准运营流程的一部分。', '', NULL, 2, 'normal', '2026-04-07 12:33:38', '2026-04-07 12:33:38', '2026-04-07 12:33:27', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (710, 'DRIFT攻击调查指向朝鲜中间人接触', '针对DRIFT协议攻击的初步调查显示，有团队成员曾在行业会议上被朝鲜中间人当面接触。调查仍在进行中，此事件凸显了加密货币领域面临的地缘政治与安全风险。', '', NULL, 2, 'normal', '2026-04-07 12:33:40', '2026-04-07 12:33:40', '2026-04-07 12:33:27', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (711, 'Binance to List Equity Perpetuals', 'Binance Futures will launch USDⓈ-margined perpetual contracts for QQQUSDT, SPYUSDT, AAPLUSDT, and TSMUSDT on April 6, 2026. These contracts allow trading on the price of major ETFs and tech stocks.', '', NULL, 2, 'normal', '2026-04-07 12:33:42', '2026-04-07 12:33:42', '2026-04-07 12:33:27', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (712, 'Polymarket Integrates Pyth Pro', 'Prediction market platform Polymarket has integrated Pyth Pro''s oracle services to power its traditional asset markets. The move aims to enhance data reliability for markets tied to real-world events and equities.', '', NULL, 2, 'normal', '2026-04-07 12:33:44', '2026-04-07 12:33:44', '2026-04-07 12:33:27', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (713, 'Binance Adds MU, SNDK Perpetuals', 'Binance Futures will list USDⓈ-margined equity perpetual contracts for MUUSDT and SNDKUSDT on April 7, 2026. The new contracts expand the exchange''s offerings for trading stock-related derivatives.', '', NULL, 2, 'normal', '2026-04-07 12:33:46', '2026-04-07 12:33:46', '2026-04-07 12:33:27', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (714, 'Binance to Delist Perpetual Contracts', 'Binance Futures announced it will delist multiple perpetual contracts on April 8 and 9, 2026. The exchange regularly reviews its offerings and may remove low-liquidity or underperforming contracts.', '', NULL, 2, 'normal', '2026-04-07 12:33:48', '2026-04-07 12:33:48', '2026-04-07 12:33:27', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (715, '股市承压油价跳涨', '随着特朗普对伊朗的最后期限临近，股市表现挣扎，而油价跳涨。地缘政治风险升温推高能源价格，同时打压了风险偏好，导致股市承压。', '', NULL, 2, 'normal', '2026-04-07 12:33:51', '2026-04-07 12:33:51', '2026-04-07 12:33:27', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (716, '特朗普对伊言论升级 油价延续涨势', '随着特朗普对伊朗的言论升级，原油价格延续涨势。市场担忧中东紧张局势可能扰乱全球石油供应，推动布伦特和WTI原油期货价格走高。', '', NULL, 2, 'normal', '2026-04-07 12:33:53', '2026-04-07 12:33:53', '2026-04-07 12:33:27', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (753, 'Polymarket采用Pyth Pro提供数据', '预测市场平台Polymarket宣布采用Pyth Pro为其传统资产市场提供喂价服务，旨在提升其市场数据的准确性和可靠性。', '', NULL, 2, 'normal', '2026-04-07 12:37:25', '2026-04-07 12:37:25', '2026-04-07 12:37:23', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (754, '币安将上线MU和SNDK永续合约', '币安合约交易平台将于2026年4月7日上线MUUSDT和SNDKUSDT的美元本位股权永续合约，为交易者提供更多美股相关衍生品选择。', '', NULL, 2, 'normal', '2026-04-07 12:37:27', '2026-04-07 12:37:27', '2026-04-07 12:37:23', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (755, '股市承压 油价因伊朗期限跳涨', '随着特朗普设定的伊朗协议最后期限临近，全球股市表现挣扎，而原油价格大幅跳涨。地缘政治紧张局势加剧了市场波动。', '', NULL, 2, 'normal', '2026-04-07 12:37:30', '2026-04-07 12:37:30', '2026-04-07 12:37:23', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (756, 'Chaos Labs退出AAVE风险提供商角色', 'DeFi风险管理商Chaos Labs表示，AAVE计划迁移至V4版本引入了其不愿承担的风险，因此决定退出。AAVE方面则表示，Chaos Labs希望作为唯一风险服务提供商获得完全控制权。', '', NULL, 2, 'normal', '2026-04-07 12:37:32', '2026-04-07 12:37:32', '2026-04-07 12:37:23', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (757, 'Polymarket升级交易所基础设施', '预测市场平台Polymarket将在未来几周升级其交易所基础设施，引入新合约和由USDC支持的代币，同时逐步淘汰桥接稳定币USDC.e。', '', NULL, 2, 'normal', '2026-04-07 12:37:34', '2026-04-07 12:37:34', '2026-04-07 12:37:23', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (758, '美参议院确认加密市场结构法案时间表', '美国参议院银行委员会成员比尔·哈格蒂确认，加密市场结构法案的推进时间表定于四月。他承认在国会推进该法案前“仍有大量工作要做”，并宣布下周起将重新关注此事。', '', NULL, 2, 'normal', '2026-04-07 12:37:36', '2026-04-07 12:37:36', '2026-04-07 12:37:23', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (759, 'Bitcoin May Hit $110K as Strategy Buys BTC', 'Bitcoin may invalidate its bear flag setup and target $110,000 as an entity named ''Strategy'' bought 46,233 BTC in just over a month, outpacing the new supply of 16,200 BTC in the same period.', '', NULL, 2, 'normal', '2026-04-07 12:37:38', '2026-04-07 12:37:38', '2026-04-07 12:37:23', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (760, '比特币网络活动激增', 'CryptoQuant报告称，比特币网络活动在数月下降后“刚刚急剧上升”。其指数跟踪地址、交易、UTXO和区块空间需求。目前每日比特币交易数约为61.5万笔，为近期高点。', '', NULL, 2, 'normal', '2026-04-07 12:37:40', '2026-04-07 12:37:40', '2026-04-07 12:37:23', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (761, 'Solana基金会加强DeFi安全', 'Solana基金会宣布推出STRIDE审计框架和SIRN网络，以增强生态安全。此前Drift协议攻击调查揭示更多细节。SOL报价79.70美元，76-78美元为强支撑位。2026年第一季度DeFi损失达1.68亿美元。', '', NULL, 2, 'normal', '2026-04-07 12:37:42', '2026-04-07 12:37:42', '2026-04-07 12:37:23', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (762, '$10B Ethereum Bet Puts BitMine in Focus', 'A record 38.8 million ETH is now staked, adding to the narrative around Ethereum''s security and yield. The massive stake is drawing attention to BitMine ahead of its planned NYSE listing.', '', NULL, 2, 'normal', '2026-04-07 12:37:44', '2026-04-07 12:37:44', '2026-04-07 12:37:23', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (763, 'Solana Enhances Security with New Tools', 'Solana Foundation announces the STRIDE audit framework and SIRN network to bolster DeFi security. The move follows the Drift hack investigation, with SOL trading at $79.70 and strong supports at $76-78.', '', NULL, 2, 'normal', '2026-04-07 12:37:47', '2026-04-07 12:37:47', '2026-04-07 12:37:23', 'en', '') ON CONFLICT DO NOTHING;
