INSERT INTO public.flash_news VALUES (725, '比特币期权市场暗示下行风险', '比特币期权市场正悄然为一次重大的下行波动定价。衍生品交易员似乎正在对冲潜在的地缘政治或宏观经济冲击带来的风险。', '', NULL, 2, 'normal', '2026-04-07 12:34:47', '2026-04-07 12:34:47', '2026-04-07 12:34:28', 'zh', '') ON CONFLICT DO NOTHING;
