INSERT INTO public.flash_news VALUES (727, '百亿美元以太坊质押引关注', '目前已有3880万枚ETH被质押，价值约百亿美元。这一纪录为即将在纽交所上市的BitMine增添了叙事，凸显了以太坊质押生态的规模。', '', NULL, 2, 'normal', '2026-04-07 12:34:51', '2026-04-07 12:34:51', '2026-04-07 12:34:28', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (728, '加密货币在伊朗局势中持稳', '特朗普为伊朗协议设定周二晚最后期限，威胁若无协议将摧毁伊朗基础设施，油价跳涨至112美元上方。加密货币市场回吐周一停火协议带来的涨幅，但整体持稳。', '', NULL, 2, 'normal', '2026-04-07 12:34:53', '2026-04-07 12:34:53', '2026-04-07 12:34:28', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (765, 'DRIFT协议或遭超2亿美元攻击', '链上数据显示，DRIFT PROTOCOL可能遭受漏洞攻击，损失金额超过2亿美元。安全事件具体细节仍在调查中。', '', NULL, 2, 'normal', '2026-04-07 12:38:30', '2026-04-07 12:38:30', '2026-04-07 12:38:28', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (766, 'Polymarket采用Pyth Pro喂价', '预测市场平台Polymarket宣布采用Pyth Pro为其传统资产市场提供价格数据支持，以提升其市场定价的准确性与可靠性。', '', NULL, 2, 'normal', '2026-04-07 12:38:32', '2026-04-07 12:38:32', '2026-04-07 12:38:28', 'zh', '') ON CONFLICT DO NOTHING;
