INSERT INTO public.flash_news VALUES (768, 'Chaos Labs退出AAVE风险提供商角色', 'DeFi风险管理器Chaos Labs表示，AAVE计划迁移至V4版本引入了其不愿承担的风险，因此决定退出。AAVE方面则表示，Chaos Labs希望作为唯一风险服务提供商获得完全控制权。', '', NULL, 2, 'normal', '2026-04-07 12:38:36', '2026-04-07 12:38:36', '2026-04-07 12:38:28', 'zh', '') ON CONFLICT DO NOTHING;
