INSERT INTO public.flash_news VALUES (854, '加密市场安全港提案提交白宫审议', '一项旨在为加密市场提供监管明确性的“安全港”提案已提交至白宫进行审查，这被视为美国加密监管进程中的关键一步。', '原source', NULL, 2, 'normal', '2026-04-07 12:46:48', '2026-04-07 12:46:48', '2026-04-07 12:46:29', 'zh', '') ON CONFLICT DO NOTHING;
