INSERT INTO public.flash_news VALUES (1473, '比特币、以太坊、Solana持稳，特朗普设伊朗协议最后期限', '在特朗普为伊朗协议设定周二晚间最后期限的背景下，主要加密货币比特币、以太坊和Solana价格保持相对稳定。', '', NULL, 2, 'normal', '2026-04-07 13:54:45', '2026-04-07 13:54:45', '2026-04-07 13:54:34', 'zh', '') ON CONFLICT DO NOTHING;
