INSERT INTO public.flash_news VALUES (1081, '金价持稳 市场关注特朗普伊朗最后期限', '路透社报道，由于特朗普设定的伊朗问题最后期限临近，市场保持谨慎，黄金价格持稳。地缘政治风险为金价提供了支撑。', 'Reuters', NULL, 2, 'normal', '2026-04-07 13:10:32', '2026-04-07 13:10:32', '2026-04-07 13:10:26', 'zh', '') ON CONFLICT DO NOTHING;
