INSERT INTO public.flash_news VALUES (1515, '币安将上线MU和SNDK股票永续合约', '币安合约平台计划于2026年4月7日上线MUUSDT和SNDKUSDT美元本位股票永续合约。这些合约将追踪美光科技和闪迪公司的股价，为交易者提供更多样化的股票衍生品选择。', '', NULL, 2, 'normal', '2026-04-07 13:58:35', '2026-04-07 13:58:35', '2026-04-07 13:58:26', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (1516, '币安合约将下架多个永续合约', '币安合约宣布将于2026年4月8日及4月9日下架多个永续合约交易对。平台建议用户在截止日期前平仓或转移头寸。具体下架合约名单已在官方公告中列出。', '', NULL, 2, 'normal', '2026-04-07 13:58:37', '2026-04-07 13:58:37', '2026-04-07 13:58:26', 'zh', '') ON CONFLICT DO NOTHING;
