INSERT INTO public.flash_news VALUES (1768, 'Anthropic签多吉瓦算力协议，成矿工新对手', '人工智能公司Anthropic签署了一项涉及多吉瓦电力计算的协议，这使其成为比特币矿工在获取廉价电力资源方面的新竞争对手。能源竞争可能加剧。', '', NULL, 2, 'normal', '2026-04-07 14:31:45', '2026-04-07 14:31:45', '2026-04-07 14:31:36', 'zh', '') ON CONFLICT DO NOTHING;
