INSERT INTO public.flash_news VALUES (1815, 'Japan Cuts Crypto Tax to 20.315%', 'Japan will implement a flat 20.315% separate tax on crypto gains by 2028, down from a top rate of 55%. The reform includes a three-year loss carryforward, aligning crypto taxation with traditional stocks.', '', NULL, 2, 'normal', '2026-04-07 14:35:48', '2026-04-07 14:35:48', '2026-04-07 14:35:27', 'en', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (1816, 'Solana24小时跌2.2%报79.48美元', 'Solana（SOL）当前交易价格为79.48美元，24小时跌幅为2.2%，市值约为456亿美元。价格在特朗普设定伊朗协议最后期限的背景下保持相对稳定。', '', NULL, 2, 'normal', '2026-04-07 14:35:51', '2026-04-07 14:35:51', '2026-04-07 14:35:27', 'zh', '') ON CONFLICT DO NOTHING;
INSERT INTO public.flash_news VALUES (1817, 'Cardano24小时跌5.2%报0.24美元', 'Cardano（ADA）价格现报0.24美元，过去24小时大幅下跌5.2%，当前市值约为90亿美元。市场整体情绪谨慎，多数主流加密货币出现下跌。', '', NULL, 2, 'normal', '2026-04-07 14:35:53', '2026-04-07 14:35:53', '2026-04-07 14:35:27', 'zh', '') ON CONFLICT DO NOTHING;
